import org.jfree.data.xy.OHLCDataset;
import org.jfree.data.xy.OHLCSeries;
import org.jfree.data.xy.OHLCSeriesCollection;
import org.jfree.data.time.TimeSeries;
import org.jfree.data.time.TimeSeriesCollection;
import org.jfree.data.time.Day;

import java.awt.*;
import java.awt.image.BufferedImage;
import java.util.Calendar;
import java.util.Date;
import java.util.Random;
import java.util.TimeZone;

public class ChartImageGenerator {

    public BufferedImage generateChartImage() {
        // 创建数据集
        OHLCDataset dataset = createOHLCDataset();
        TimeSeriesCollection maDataset = createMovingAverageDataset(dataset);

        // 创建图表
        JFreeChart chart = createChart(dataset, maDataset);

        // 渲染成 BufferedImage
        BufferedImage chartImage = chart.createBufferedImage(800, 600);
        return chartImage;
    }

    private OHLCDataset createOHLCDataset() {
        OHLCSeries series = new OHLCSeries("K Line Series");
        Calendar calendar = Calendar.getInstance(TimeZone.getDefault());
        calendar.add(Calendar.DAY_OF_YEAR, -100);
        Random rand = new Random();

        for (int i = 0; i < 100; i++) {
            double open = 100 + rand.nextDouble() * 10;
            double close = 100 + rand.nextDouble() * 10;
            double low = Math.min(open, close) - rand.nextDouble() * 5;
            double high = Math.max(open, close) + rand.nextDouble() * 5;
            series.add(new Day(calendar.getTime()), open, high, low, close);
            calendar.add(Calendar.DAY_OF_YEAR, 1);
        }

        OHLCSeriesCollection dataset = new OHLCSeriesCollection();
        dataset.addSeries(series);
        return dataset;
    }

    private TimeSeriesCollection createMovingAverageDataset(OHLCDataset ohlcDataset) {
        TimeSeries series = new TimeSeries("20-Day MA");
        int period = 20;
        int endIndex = ohlcDataset.getItemCount(0);

        for (int i = period - 1; i < endIndex; i++) {
            double sum = 0.0;
            for (int j = 0; j < period; j++) {
                sum += ohlcDataset.getCloseValue(0, i - j);
            }
            double average = sum / period;
            series.add(new Day(new Date(ohlcDataset.getX(0, i).longValue())), average);
        }

        return new TimeSeriesCollection(series);
    }

    private JFreeChart createChart(OHLCDataset ohlcDataset, TimeSeriesCollection maDataset) {
        JFreeChart chart = ChartFactory.createCandlestickChart(
                null, // 无标题
                "Date", // X轴标签
                "Price", // Y轴标签
                ohlcDataset,
                false
        );

        XYPlot plot = chart.getXYPlot();
        plot.setDomainPannable(true);
        plot.setRangePannable(true);

        // 设置绘图区域和图表背景
        plot.setBackgroundPaint(Color.BLACK);
        plot.setOutlineVisible(false); // 确保绘图区无边框
        chart.setBackgroundPaint(Color.BLACK);
        chart.setBorderVisible(false); // 确保整个图表无边框

        // 调用该方法来最小化显示
        customizePlotForMinimalDisplay(plot, chart);

        // 创建和配置蜡烛图渲染器
        CandlestickRenderer renderer = new CandlestickRenderer() {
            @Override
            public Paint getItemOutlinePaint(int row, int column) {
                OHLCDataset dataset = (OHLCDataset) this.getPlot().getDataset();
                double open = dataset.getOpenValue(row, column);
                double close = dataset.getCloseValue(row, column);
                return close > open ? new Color(0, 128, 0) : new Color(165, 42, 42);
            }
        };
        renderer.setSeriesPaint(0, new Color(192, 80, 77)); // 蜡烛填充色
        renderer.setDownPaint(new Color(192, 80, 77)); // 下跌填充色
        renderer.setUpPaint(new Color(155, 187, 89));   // 上涨填充色
        renderer.setDrawVolume(false); // 如果需要体积线，可以设置为true

        plot.setRenderer(renderer);

        // 设置均线渲染器
        XYLineAndShapeRenderer lineRenderer = new XYLineAndShapeRenderer(true, false);
        lineRenderer.setSeriesPaint(0, Color.RED);
        plot.setDataset(1, maDataset);
        plot.setRenderer(1, lineRenderer);

        // 设置纵轴范围，不从零开始
        NumberAxis rangeAxis = (NumberAxis) plot.getRangeAxis();
        rangeAxis.setAutoRangeIncludesZero(false);

        return chart;
    }

    private void customizePlotForMinimalDisplay(XYPlot plot, JFreeChart chart) {
        // 隐藏轴标签和刻度
        plot.getDomainAxis().setLabel(null);
        plot.getDomainAxis().setTickLabelsVisible(false);
        plot.getRangeAxis().setLabel(null);
        plot.getRangeAxis().setTickLabelsVisible(false);

        // 隐藏图例
        chart.removeLegend();
    }

    public static void main(String[] args) {
        BufferedImage image = new ChartImageGenerator().generateChartImage();
        // 使用图像进行需要的操作，比如保存或展示
    }
}
```

